-- SAPFM Card Catalog — Migration 03: Seed cards (Chipstone 1996 pilot batch)

INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Seventeenth-Century Joinery from Braintree, Massachusetts: The Savell Shop Tradition', '["Peter Follansbee", "John D. Alexander"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'A detailed technical study of a three-generation Braintree joinery shop, tracing the Savell family''s distinctive mortise-and-tenon variant â€” an offset drawbored joint not found in Plymouth Colony or Boston work â€” through chests, cupboards, and desk boxes spanning 1640â€“1700. Includes scale drawings of joint geometry and wood species analysis. Essential reading for anyone working in early joined furniture construction.', '["Early Colonial", "William & Mary"]', '["Case pieces"]', '["New England", "Boston"]', '["Construction / Technique", "Regional Style", "Biography / Shops"]', '["William Savell Sr.", "William Savell Jr.", "John Savell"]', 1, 'https://chipstone.org/article.php/222/American-Furniture-1996/Seventeenth-Century-Joinery-from-Braintree,-Massachusetts:-The-Savell-Shop-Tradition', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Frog Backs and Turkey Legs: The Nomenclature of Vernacular Seating Furniture, 1740â€“1850', '["Nancy Goyne Evans"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'A systematic study of the period trade terminology used by Windsor and vernacular chairmakers in account books, daybooks, and price lists, covering slat-back, banister-back, Windsor, and related forms. Establishes the authentic names craftsmen used for chair parts, back types, and turned elements â€” essential grounding for anyone studying or describing period seating. One of Evans''s foundational contributions to Windsor scholarship.', '["Queen Anne", "Chippendale", "Federal / Neoclassical"]', '["Windsor", "Vernacular", "Seating"]', '["National / Survey", "Philadelphia", "New England"]', '["Terminology / Nomenclature", "Trade / Commerce", "Construction / Technique"]', '["Francis Trumble", "Amos Denison Allen", "Joseph Henzey", "Jared Chesnut"]', 1, 'https://chipstone.org/article.php/216/American-Furniture-1996/Frog-Backs-and-Turkey-Legs:-The-Nomenclature-of-Vernacular-Seating-Furniture,-1740%E2%80%931850', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Louis Comfort Tiffany and the Reform Movement in Furniture Design: The J. Matthew Meier and Ernest Hagen Commission of 1882â€“1885', '["Milo M. Naeve"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'Documents Tiffany''s previously unrecognized role as a furniture designer through a surviving breakfast suite commissioned from Manhattan cabinetmakers Meier and Hagen. Analyzes the suite''s deliberate simplicity â€” pine and maple, enamel paint, exposed construction details â€” as a direct response to the English Reform movement. Uses original Meier-Hagen order books to establish attribution, dating, and cost. Strong example of shop records used to nail attribution.', '["Victorian"]', '["Seating", "Tables"]', '["New York City"]', '["Attribution", "Design Sources", "Shop Records", "Biography / Shops"]', '["J. Matthew Meier", "Ernest Hagen", "Louis Comfort Tiffany"]', 1, 'https://chipstone.org/article.php/214/American-Furniture-1996/Louis-Comfort-Tiffany-and-the-Reform-Movement-in-Furniture-Design:-The-J.-Matthew-Meier-and-Ernest-Hagen-Commission-of-1882%E2%80%931885', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('The Rococo, the Grotto, and the Philadelphia High Chest', '["Jonathan Prown", "Richard Miller"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'Examines the iconographic program of Philadelphia high chest carving â€” particularly grotto and naturalistic motifs â€” as a deliberate synthesis of European Rococo sources rather than simple pattern book copying. Closely analyzes specific carved examples against English and continental precedents and argues for a distinctly American Rococo vocabulary. Valuable for understanding the intellectual ambition behind Philadelphia carving.', '["Chippendale"]', '["Case pieces"]', '["Philadelphia"]', '["Carving / Ornament", "Design Sources", "Regional Style"]', '[]', 1, 'https://chipstone.org/article.php/229/American-Furniture-1996/The-Rococo,-the-Grotto,-and-the-Philadelphia-High-Chest', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Is It Phyfe?', '["Deborah Dependahl Waters"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'A methodological examination of the attribution problems surrounding furniture associated with Duncan Phyfe''s New York shop, arguing that the Phyfe name has been applied far too broadly. Surveys the documentary evidence â€” bills, labels, family descent â€” that legitimately supports attribution and proposes a rigorous framework for evaluating contested pieces. A useful model for attribution methodology beyond Phyfe specifically.', '["Federal / Neoclassical"]', '["Seating", "Tables"]', '["New York City"]', '["Attribution", "Connoisseurship", "Shop Records"]', '["Duncan Phyfe"]', 1, 'https://chipstone.org/article.php/217/American-Furniture-1996/Is-It-Phyfe', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Beautiful Specimens, Elegant Patterns: New York Furniture for the Charleston Market, 1810â€“1840', '["Maurie D. McInnis", "Robert A. Leath"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'Documents the substantial trade in New York-made furniture to Charleston, South Carolina, using merchant records, estate inventories, and surviving pieces to map the commercial and stylistic exchange. Shows how Charleston taste influenced what New York shops produced and exported southward â€” a model of how regional market analysis enriches attribution and dating.', '["Federal / Neoclassical", "Empire"]', '["Case pieces", "Seating", "Tables"]', '["New York City", "Charleston", "Southern"]', '["Trade / Commerce", "Regional Style", "Social History"]', '[]', 1, 'https://chipstone.org/article.php/235/American-Furniture-1996/Beautiful-Specimens,-Elegant-Patterns:--New-York-Furniture-for-the-Charleston-Market,-1810%E2%80%931840', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Boston and New York Leather Chairs: A Reappraisal', '["Roger Gonzales", "Daniel Putnam Brown, Jr."]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'Reexamines attribution criteria for early eighteenth-century leather chairs made in Boston and New York, using constructional analysis â€” turned elements, stretcher profiles, seat rail joinery â€” to distinguish between the two centers. Challenges several received attributions and proposes revised diagnostic criteria. Part of a series of interrelated Chipstone articles substantially rewriting Boston colonial chairmaking history.', '["William & Mary", "Queen Anne"]', '["Seating"]', '["Boston", "New York City"]', '["Attribution", "Construction / Technique", "Regional Style"]', '[]', 1, 'https://chipstone.org/article.php/236/American-Furniture-1996/Boston-and-New-York-leather-Chairs:-A-Reappraisal', 'approved', datetime('now'), datetime('now'));
INSERT OR IGNORE INTO library_cards (title, authors, year, source, source_key, card_type, description, period, form, region, topic, makers, is_free, view_url, status, created_at, updated_at) VALUES ('Immigrant Carvers and the Development of the Rococo Style', '["Luke Beckerdite"]', 1996, 'Chipstone Foundation â€” American Furniture', 'chipstone', 'article', 'Traces the introduction of Rococo carving to Philadelphia and New York through immigrant craftsmen from Britain and the continent, identifying specific carvers through stylistic analysis across multiple commissions. Establishes individual carving hands and their influence on the broader development of American Rococo ornament. Beckerdite''s methodology for identifying anonymous carvers through their work is the model for this kind of research.', '["Chippendale"]', '["Case pieces", "Seating"]', '["Philadelphia", "New York City"]', '["Carving / Ornament", "Regional Style", "Attribution", "Immigration"]', '[]', 1, 'https://chipstone.org/article.php/238/American-Furniture-1996/Immigrant-Carvers-and-the-Development-of-the-Rococo-Syle', 'approved', datetime('now'), datetime('now'));
